import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void classicWindow() {
        // windows: [1,4,2,10]=17, [4,2,10,2]=18, [2,10,2,3]=17,
        // [10,2,3,1]=16, [2,3,1,0]=6, [3,1,0,20]=24
        assertEquals(24, new Solution().maxKWindowSum(new int[]{1, 4, 2, 10, 2, 3, 1, 0, 20}, 4));
    }

    @Test
    void smallWindow() {
        assertEquals(500, new Solution().maxKWindowSum(new int[]{100, 200, 300}, 2));
    }

    @Test
    void wholeArray() {
        assertEquals(10, new Solution().maxKWindowSum(new int[]{1, 2, 3, 4}, 4));
    }

    @Test
    void kEqualsOne() {
        assertEquals(7, new Solution().maxKWindowSum(new int[]{3, 7, 2}, 1));
    }

    @Test
    void allNegatives() {
        // windows of 2: [-1,-2]=-3, [-2,-3]=-5. Max=-3.
        assertEquals(-3, new Solution().maxKWindowSum(new int[]{-1, -2, -3}, 2));
    }
}
